// Nó de CÓDIGO (determinístico), não nó de IA — conciliação Invoice x Packing List x B/L.
// Compara campos-chave entre os três documentos e emite divergências estruturadas.
// Esqueleto: preencher com as regras reais de conciliação na Semana 2.
const dados = $input.first().json;
const divergencias = [];
// TODO Semana 2: comparar quantidade, peso, valor, NCM, partes entre invoice/packingList/bl.
return [{ json: { divergencias, origem: dados } }];

// Nó de CÓDIGO (não IA) — Guardrail 1 (grounding obrigatório) do INFRA_COST_GUARDRAILS.md.
// Descarta qualquer apontamento cuja citação não tenha norma.id rastreável na base.
const apontamentos = ($input.first().json.apontamentos) || [];
const validos = [];
for (const a of apontamentos) {
  if (a.norma_citada_id) {
    validos.push(a);
  } else {
    validos.push({ ...a, descricao: 'sem base normativa localizada', norma_citada_id: null, bloqueado_por_grounding: true });
  }
}
return [{ json: { apontamentos: validos } }];
